# Using Guardrails-style structured output with Anthropic's native tool use
import anthropic, json
from typing import TypedDict

class InvoiceSummary(TypedDict):
    vendor: str
    total: float
    currency: str

client = anthropic.Anthropic()

tools = [{
    "name": "record_invoice",
    "description": "Record structured invoice data",
    "input_schema": {
        "type": "object",
        "properties": {
            "vendor": {"type": "string"},
            "total": {"type": "number"},
            "currency": {"type": "string", "pattern": "^[A-Z]{3}$"}
        },
        "required": ["vendor", "total", "currency"]
    }
}]

resp = client.messages.create(
    model="claude-haiku-4-5-20251001",
    max_tokens=200,
    tools=tools,
    tool_choice={"type": "auto"},
    messages=[{"role": "user", "content": "Invoice from Acme Inc, total $1,250 USD"}],
)

for block in resp.content:
    if block.type == "tool_use" and block.name == "record_invoice":
        data: InvoiceSummary = block.input
        print(json.dumps(data, indent=2))
